	$templateCode = str_replace('<%%UPLOADFILE(collaboration_date)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(tih_payment)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(charging_status)%%>', '', $templateCode);
