		if( $dvprint) $templateCode = str_replace('<%%VALUE(tbi_name)%%>', safe_html($urow['tbi_name']), $templateCode);
		if(!$dvprint) $templateCode = str_replace('<%%VALUE(tbi_name)%%>', html_attr($row['tbi_name']), $templateCode);
